+/// Download a starter from GitHub, storing it according to `mode` before copying into `dest`.
+fn clone_remote_starter(
+    starter: &RemoteStarter,
+    dest: Option<&str>,
+    mode: RemoteCloneMode,
+) -> Result<PathBuf> {
+    match mode {
+        RemoteCloneMode::Tar => clone_remote_starter_tar(starter, dest),
+        RemoteCloneMode::Git => clone_remote_starter_git(starter, dest),
     }
 }

+fn clone_remote_starter_tar(starter: &RemoteStarter, dest: Option<&str>) -> Result<PathBuf> {
+    let project_dirs = ProjectDirs::from("", "", "jump-start")
+        .unwrap_or_else(|| panic!("Could not find OS project directory"));
+
+    let cache_dir = project_dirs
+        .cache_dir()
+        .join("github")
+        .join(&starter.github_username)
+        .join(&starter.github_repo);
+
+    let tar_url = format!(
+        "https://www.github.com/{}/{}/archive/HEAD.tar.gz",
+        starter.github_username, starter.github_repo
+    );
+    let tar_path = download_tar(&tar_url, &cache_dir)
+        .with_context(|| format!("Downloading tar {}", tar_url))?;
+    let subdir = format!("{}/{}", starter.group, starter.name);
+    let cache_dest = cache_dir.join(&subdir);
+
+    extract_tar_subdir(&tar_path, &subdir, &cache_dest)
+        .with_context(|| format!("Extracting tar {} into {:?}", tar_url, cache_dest))?;
+    debug!(
+        "Extracted {:?} with subdir {:?} to {:?}",
+        tar_path, subdir, cache_dest
+    );
+
+    let final_dest = get_final_dest(&cache_dest, dest)?;
+
+    copy_dir_contents(&cache_dest, &final_dest).with_context(|| format!("Copying dir contents"))?;
+    Ok(final_dest)
+}
+
+fn clone_remote_starter_git(starter: &RemoteStarter, dest: Option<&str>) -> Result<PathBuf> {
+    let project_dirs = ProjectDirs::from("", "", "jump-start")
+        .unwrap_or_else(|| panic!("Could not find OS project directory"));
+
+    let cache_dir = project_dirs
+        .cache_dir()
+        .join("github")
+        .join(&starter.github_username)
+        .join(&starter.github_repo);
+    let repo_cache_dir = cache_dir.join("_git_repo");
+
+    ensure_git_repo(&repo_cache_dir, starter)?;
+
+    let starter_path_full = repo_cache_dir.join(&starter.group).join(&starter.name);
+    if !starter_path_full.exists() {
+        anyhow::bail!(
+            "Starter {}/{} not found in repository {}",
+            starter.group,
+            starter.name,
+            repo_cache_dir.display()
+        );
+    }
+
+    let final_dest = get_final_dest(&starter_path_full, dest)?;
+
+    copy_dir_contents(&starter_path_full, &final_dest)
+        .with_context(|| format!("Copying dir contents"))?;
+
+    Ok(final_dest)
+}
+
+fn ensure_git_repo(repo_cache_dir: &Path, starter: &RemoteStarter) -> Result<()> {
+    let repo_url = format!(
+        "https://www.github.com/{}/{}.git",
+        starter.github_username, starter.github_repo
+    );
+
+    if repo_cache_dir.join(".git").exists() {
+        if let Err(err) = update_git_repo(repo_cache_dir) {
+            warn!(
+                "Failed to update cached git repo at {}: {}. Re-cloning.",
+                repo_cache_dir.display(),
+                err
+            );
+            fs::remove_dir_all(repo_cache_dir).with_context(|| {
+                format!("Removing stale git cache at {}", repo_cache_dir.display())
+            })?;
+            clone_git_repo(repo_cache_dir, &repo_url)?;
+        }
+    } else {
+        if repo_cache_dir.exists() {
+            fs::remove_dir_all(repo_cache_dir)
+                .with_context(|| format!("Clearing git cache at {}", repo_cache_dir.display()))?;
+        }
+        clone_git_repo(repo_cache_dir, &repo_url)?;
+    }
+
+    Ok(())
+}
+
+fn clone_git_repo(repo_cache_dir: &Path, repo_url: &str) -> Result<()> {
+    if let Some(parent) = repo_cache_dir.parent() {
+        fs::create_dir_all(parent)?;
+    }
+
+    info!("Cloning {} into {}", repo_url, repo_cache_dir.display());
+
+    let status = Command::new("git")
+        .arg("clone")
+        .arg(repo_url)
+        .arg(repo_cache_dir)
+        .status()
+        .with_context(|| format!("Failed to run git clone {}", repo_url))?;
+
+    if !status.success() {
+        anyhow::bail!("git clone {} exited with status {}", repo_url, status);
+    }
+
+    Ok(())
+}
+
+fn update_git_repo(repo_cache_dir: &Path) -> Result<()> {
+    info!("Updating cached git repo at {}", repo_cache_dir.display());
+
+    let fetch_status = Command::new("git")
+        .arg("-C")
+        .arg(repo_cache_dir)
+        .arg("fetch")
+        .arg("--all")
+        .arg("--prune")
+        .status()
+        .with_context(|| format!("Failed to run git fetch in {}", repo_cache_dir.display()))?;
+
+    if !fetch_status.success() {
+        anyhow::bail!(
+            "git fetch in {} exited with status {}",
+            repo_cache_dir.display(),
+            fetch_status
+        );
+    }
+
+    let reset_status = Command::new("git")
+        .arg("-C")
+        .arg(repo_cache_dir)
+        .arg("reset")
+        .arg("--hard")
+        .arg("origin/HEAD")
+        .status()
+        .with_context(|| format!("Failed to run git reset in {}", repo_cache_dir.display()))?;
+
+    if !reset_status.success() {
+        anyhow::bail!(
+            "git reset in {} exited with status {}",
+            repo_cache_dir.display(),
+            reset_status
+        );
+    }
+
+    Ok(())
+}
+
