+/// Clone or update a git repository.
+/// If the repository already exists, it pulls the latest changes.
+/// Returns the path to the cloned/updated repository.
+fn clone_or_pull_git_repo(git_url: &str, cache_dir: &Path) -> Result<PathBuf> {
+    fs::create_dir_all(cache_dir)?;
+
+    // Check if the repository already exists
+    if cache_dir.join(".git").exists() {
+        debug!("Git repository already exists at {:?}, pulling latest changes", cache_dir);
+        let repo = Repository::open(cache_dir)
+            .with_context(|| format!("Failed to open repository at {:?}", cache_dir))?;
+
+        // Fetch from origin
+        let mut remote = repo
+            .find_remote("origin")
+            .with_context(|| "Failed to find 'origin' remote")?;
+
+        remote.fetch(&["main"], None, None)
+            .or_else(|_| {
+                // Try 'master' if 'main' fails
+                remote.fetch(&["master"], None, None)
+            })
+            .with_context(|| format!("Failed to fetch from {}", git_url))?;
+
+        info!("Pulled latest changes from {}", git_url);
+        Ok(cache_dir.to_path_buf())
+    } else {
+        // Clone the repository
+        debug!("Cloning repository from {}", git_url);
+        info!("Cloning {} to {:?}", git_url, cache_dir);
+
+        Repository::clone(git_url, cache_dir)
+            .with_context(|| format!("Failed to clone repository from {}", git_url))?;
+
+        Ok(cache_dir.to_path_buf())
+    }
+}
